/**
 * Annotation parser for `@dabbler:outsource-review("reason")` markers.
 *
 * Source-code annotations are the second of two surfaces operators use to
 * flag a decision for cross-provider review (the first being the
 * `dabbler.flagDecisionForReview` command). The scanner registered in
 * `commands/scanAnnotationsForActiveSet.ts` walks workspace files, calls
 * `findAnnotations` on each file's text, and appends results to the
 * active session set's `decision-review-queue.jsonl`.
 *
 * Comment styles recognized:
 *   - Python / shell / YAML:    # @dabbler:outsource-review("...")
 *   - JS/TS/Java/C#/C/C++/Go:   // @dabbler:outsource-review("...")
 *
 * Each comment style is honored regardless of file extension — the parser
 * does not assume the caller has filtered files by language. This lets
 * mixed-language repos (Python tests with `// ...` in a comment, or shell
 * scripts with hashbang plus `//`) pick up annotations either way.
 */
export interface Annotation {
  /** ISO timestamp when the annotation was discovered. */
  ts: string;
  /** Operator-supplied reason text from inside the parentheses. */
  reason: string;
  /** Always "annotation" for findAnnotations output. */
  source: "annotation";
  /** Workspace-relative path with forward slashes (POSIX style). */
  file: string;
  /** 1-based line number. */
  line: number;
}

/**
 * Match an `@dabbler:outsource-review("...")` annotation.
 *
 * The reason capture stops at the first unescaped closing double-quote.
 * Backslash-escaped quotes (`\"`) inside the reason are tolerated and
 * unescaped in the returned `reason`. Escaped backslashes (`\\`) are
 * unescaped to `\`.
 *
 * The leading comment marker is either `#` or `//`; arbitrary whitespace
 * between the marker and the `@` is allowed so callers can format the
 * annotation naturally in source.
 *
 * Raw newlines (`\r` / `\n`) are explicitly forbidden inside the reason —
 * annotations are line-comment syntax, so an unterminated `"` on one
 * line must NOT match a closing `"` on a later line (verifier-flagged
 * false-positive shape, Session 6 Slice A finding).
 */
const ANNOTATION_RE =
  /(?:#|\/\/)\s*@dabbler:outsource-review\(\s*"((?:\\.|[^"\\\r\n])*)"\s*\)/g;

/**
 * Find every annotation in `text`. Returns a list with one entry per
 * occurrence, in file order. The `file` field is the caller-supplied
 * `filePath` normalized to POSIX forward slashes; the `line` field is
 * 1-based.
 *
 * `now` is exposed for tests; production callers omit it and accept
 * `new Date().toISOString()`.
 */
export function findAnnotations(
  text: string,
  filePath: string,
  now: () => string = () => new Date().toISOString(),
): Annotation[] {
  const out: Annotation[] = [];
  // Normalize BOTH separator styles regardless of host OS — splitting on
  // path.sep only rewrites the current OS's separator, which breaks the
  // POSIX-path contract for a Windows-style input on Linux/macOS
  // (verifier-flagged host-dependent normalization, Session 6 Slice A).
  const posixPath = filePath.replace(/\\/g, "/");
  const ts = now();

  // Track line starts so we can convert byte offsets to 1-based line
  // numbers without re-scanning the prefix for every match.
  const lineStarts: number[] = [0];
  for (let i = 0; i < text.length; i++) {
    if (text.charCodeAt(i) === 10) lineStarts.push(i + 1);
  }

  ANNOTATION_RE.lastIndex = 0;
  let m: RegExpExecArray | null;
  while ((m = ANNOTATION_RE.exec(text)) !== null) {
    const reason = unescapeReason(m[1]);
    if (reason.length === 0) continue;
    const line = offsetToLine(m.index, lineStarts);
    out.push({
      ts,
      reason,
      source: "annotation",
      file: posixPath,
      line,
    });
  }
  return out;
}

/**
 * Deduplicate `incoming` annotations against an existing queue. Two
 * entries collide when their `file`, `line`, and `reason` all match —
 * the queue's `ts` and `source` are ignored. Returns only the entries
 * from `incoming` that are not already present.
 *
 * Used by `scanAnnotationsForActiveSet` so repeated scans append each
 * annotation exactly once.
 */
export function deduplicateAnnotations(
  incoming: Annotation[],
  existing: ReadonlyArray<Pick<Annotation, "file" | "line" | "reason">>,
): Annotation[] {
  const seen = new Set<string>();
  for (const entry of existing) {
    seen.add(keyFor(entry));
  }
  const out: Annotation[] = [];
  for (const ann of incoming) {
    const key = keyFor(ann);
    if (seen.has(key)) continue;
    seen.add(key);
    out.push(ann);
  }
  return out;
}

function keyFor(entry: Pick<Annotation, "file" | "line" | "reason">): string {
  return `${entry.file}�${entry.line}�${entry.reason}`;
}

function offsetToLine(offset: number, lineStarts: number[]): number {
  // Binary search for the greatest line-start <= offset. lineStarts[0]
  // is always 0, so the result is in [1, lineStarts.length].
  let lo = 0;
  let hi = lineStarts.length - 1;
  while (lo < hi) {
    const mid = (lo + hi + 1) >>> 1;
    if (lineStarts[mid] <= offset) lo = mid;
    else hi = mid - 1;
  }
  return lo + 1;
}

function unescapeReason(raw: string): string {
  let out = "";
  for (let i = 0; i < raw.length; i++) {
    const c = raw.charCodeAt(i);
    if (c === 92 /* \ */ && i + 1 < raw.length) {
      const next = raw.charAt(i + 1);
      if (next === '"' || next === "\\") {
        out += next;
        i++;
        continue;
      }
      // Unknown escape — preserve as-is. The annotation syntax is
      // deliberately permissive; tightening to "reject unknown
      // escapes" would surprise operators who write Windows paths
      // like C:\repo in a reason without realizing the parser cares.
    }
    out += raw.charAt(i);
  }
  return out;
}
